<script setup lang="ts">
import { computed, onMounted, ref } from 'vue';
import { Head } from '@inertiajs/vue3';
import { Activity, AlertTriangle, BadgeCheck, BarChart3, Check, CircleDollarSign, Database, Gauge, HeartHandshake, Info, Layers3, Megaphone, RefreshCw, Save, Server, Settings2, ShieldCheck, Sparkles, Users, Video, X } from '@lucide/vue';
import AppShell from '../../Layouts/AppShell.vue';

const loading=ref(true),saving=ref(''),error=ref(''),notice=ref(''),active=ref('feed');
const data=ref<any>({feed:{},advertising:{},environment:{},health:{}}),feed=ref<any>({}),advertising=ref<any>({});
const csrf=()=>document.querySelector<HTMLMetaElement>('meta[name="csrf-token"]')?.content??'';
const request=async(url:string,options:RequestInit={})=>{const response=await fetch(url,{credentials:'same-origin',...options,headers:{Accept:'application/json','Content-Type':'application/json','X-CSRF-TOKEN':csrf(),...(options.headers||{})}});const payload=await response.json().catch(()=>({}));if(!response.ok)throw new Error(payload.message||Object.values(payload.errors||{}).flat()[0]||'Unable to save settings.');return payload};
const load=async()=>{loading.value=true;error.value='';try{data.value=(await request('/api/v1/admin/system-settings')).data;feed.value={...data.value.feed};advertising.value={...data.value.advertising}}catch(e:any){error.value=e.message}finally{loading.value=false}};
const save=async(section:'feed'|'advertising')=>{saving.value=section;error.value='';notice.value='';try{const payload=await request(`/api/v1/admin/system-settings/${section}`,{method:'PATCH',body:JSON.stringify(section==='feed'?feed.value:advertising.value)});notice.value=payload.message;await load()}catch(e:any){error.value=e.message}finally{saving.value=''}};
const money=(cents:number)=>new Intl.NumberFormat('en-ZA',{style:'currency',currency:'ZAR',maximumFractionDigits:0}).format((cents||0)/100);
const environmentTone=computed(()=>data.value.environment.app_environment==='production'?'production':'safe');
const tabs=[{id:'feed',label:'Feed & discovery',icon:Sparkles},{id:'advertising',label:'Advertising',icon:Megaphone},{id:'system',label:'System health',icon:Server}];
onMounted(load);
</script>

<template><Head title="Platform settings"/><AppShell><main class="settings-page">
  <header class="page-head"><div><span class="eyebrow"><Settings2 :size="14"/> ADMIN CONTROLS</span><h1>Platform settings</h1><p>Control how SportsUniverse recommendations and paid campaigns behave across web and mobile.</p></div><button class="refresh" :disabled="loading" @click="load"><RefreshCw :class="{spin:loading}"/> Refresh</button></header>
  <section v-if="!loading" class="health-strip"><article><span class="health-icon blue"><Users/></span><div><strong>{{Number(data.health.users||0).toLocaleString()}}</strong><small>Members</small></div></article><article><span class="health-icon violet"><Video/></span><div><strong>{{Number(data.health.published_videos||0).toLocaleString()}}</strong><small>Published posts</small></div></article><article><span class="health-icon pink"><ShieldCheck/></span><div><strong>{{data.health.pending_reports||0}}</strong><small>Open reports</small></div></article><article><span class="health-icon amber"><CircleDollarSign/></span><div><strong>{{data.health.pending_campaigns||0}}</strong><small>Campaigns waiting</small></div></article><article><span class="health-icon" :class="data.health.failed_jobs?'red':'green'"><Activity/></span><div><strong>{{data.health.failed_jobs||0}}</strong><small>Failed jobs</small></div></article></section>
  <p v-if="notice" class="flash success"><Check/>{{notice}}<button @click="notice=''"><X/></button></p><p v-if="error" class="flash error"><AlertTriangle/>{{error}}<button @click="error=''"><X/></button></p>
  <div v-if="loading" class="loading"><RefreshCw class="spin"/><strong>Loading platform settings…</strong></div><div v-else class="settings-layout">
    <aside><div class="nav-title">Configuration</div><button v-for="tab in tabs" :key="tab.id" :class="{active:active===tab.id}" @click="active=tab.id"><component :is="tab.icon"/><span>{{tab.label}}</span></button><div class="aside-note"><BadgeCheck/><strong>Admin protected</strong><p>Every change is validated and recorded against your account.</p></div></aside>
    <section class="panel" v-if="active==='feed'"><header><span class="panel-icon purple"><Sparkles/></span><div><h2>Feed and discovery</h2><p>Shape ranking quality and the amount of content prepared for each member.</p></div><button class="save" :disabled="saving==='feed'" @click="save('feed')"><Save/>{{saving==='feed'?'Saving…':'Save changes'}}</button></header>
      <div class="section"><div class="section-copy"><h3>Ranking strategy</h3><p>Choose the primary signal used to order posts in the main feed.</p></div><div class="fields"><label class="wide">Ranking method<select v-model="feed.ranking_mode"><option value="personalized">Personalized — recommended</option><option value="engagement">Engagement — strongest posts first</option><option value="recent">Recent — newest posts first</option></select><small>Personalized balances engagement with followed accounts.</small></label><label class="toggle-row wide"><span><strong>Use fans’ selected sports</strong><small>Prioritise content matching interests selected during onboarding.</small></span><input v-model="feed.use_fan_sports" type="checkbox"/><i/></label></div></div>
      <div class="section"><div class="section-copy"><h3>Ranking weights</h3><p>Higher values give an engagement action more influence.</p></div><div class="fields"><label>View weight<input v-model.number="feed.view_weight" type="number" min="0" max="1000" step="0.01"/></label><label>Like weight<input v-model.number="feed.like_weight" type="number" min="0" max="1000" step="0.01"/></label><label>Comment weight<input v-model.number="feed.comment_weight" type="number" min="0" max="1000" step="0.01"/></label><label>Share weight<input v-model.number="feed.share_weight" type="number" min="0" max="1000" step="0.01"/></label><label class="wide">Following boost<input v-model.number="feed.follow_boost" type="number" min="0" max="100000" step="1"/><small>Only applied when Personalized ranking is selected.</small></label></div></div>
      <div class="section"><div class="section-copy"><h3>Feed capacity</h3><p>Larger values increase database, cache, and device workload.</p></div><div class="fields"><label>Posts per page<input v-model.number="feed.page_size" type="number" min="5" max="50"/></label><label>Prepared recommendations<input v-model.number="feed.recommendation_size" type="number" min="50" max="2000"/></label><p class="callout wide"><Info/>Saving feed settings clears prepared recommendations so they can rebuild using the new configuration.</p></div></div>
    </section>
    <section class="panel" v-if="active==='advertising'"><header><span class="panel-icon pink"><Megaphone/></span><div><h2>Advertising and campaigns</h2><p>Manage availability, pricing, safety checks, and sponsored feed frequency.</p></div><button class="save" :disabled="saving==='advertising'" @click="save('advertising')"><Save/>{{saving==='advertising'?'Saving…':'Save changes'}}</button></header>
      <div class="section"><div class="section-copy"><h3>Availability and safety</h3><p>Global controls affecting every paid campaign.</p></div><div class="fields"><label class="toggle-row wide"><span><strong>Allow paid campaigns</strong><small>Turning this off prevents checkout and sponsored delivery.</small></span><input v-model="advertising.enabled" type="checkbox"/><i/></label><label class="toggle-row wide"><span><strong>Require administrator review</strong><small>Campaigns need confirmed payment and approval before going live.</small></span><input v-model="advertising.require_review" type="checkbox"/><i/></label><p v-if="!advertising.require_review" class="warning wide"><AlertTriangle/>Disabling review lets paid content activate without a manual safety check.</p></div></div>
      <div class="section"><div class="section-copy"><h3>Pricing and limits</h3><p>Campaigns are prepaid in South African rand through PayFast.</p></div><div class="fields"><label>Price per 1,000 impressions<input v-model.number="advertising.cpm_cents" type="number" min="100" max="1000000"/><small>{{money(advertising.cpm_cents)}} CPM</small></label><label>Maximum duration<input v-model.number="advertising.maximum_duration_days" type="number" min="1" max="180"/><small>Days</small></label><label>Minimum daily budget<input v-model.number="advertising.minimum_daily_budget_cents" type="number" min="100"/><small>{{money(advertising.minimum_daily_budget_cents)}}</small></label><label>Maximum daily budget<input v-model.number="advertising.maximum_daily_budget_cents" type="number" min="100"/><small>{{money(advertising.maximum_daily_budget_cents)}}</small></label></div></div>
      <div class="section"><div class="section-copy"><h3>Sponsored feed balance</h3><p>Protect the member experience from repetitive advertising.</p></div><div class="fields"><label>Organic posts between ads<input v-model.number="advertising.organic_posts_between" type="number" min="3" max="50"/></label><label>Daily frequency cap<input v-model.number="advertising.frequency_cap_per_day" type="number" min="1" max="20"/><small>Per member, per campaign</small></label></div></div>
    </section>
    <section class="panel" v-if="active==='system'"><header><span class="panel-icon blue"><Server/></span><div><h2>System health</h2><p>Read-only deployment information and operational checks.</p></div><span class="environment" :class="environmentTone">{{data.environment.app_environment}}</span></header>
      <div class="system-banner" :class="data.environment.payfast_sandbox?'sandbox':'live'"><HeartHandshake/><div><strong>PayFast {{data.environment.payfast_sandbox?'sandbox':'live'}} mode</strong><p>{{data.environment.payfast_sandbox?'Test transactions are enabled. No real money should be charged.':'Payments are using the live PayFast gateway.'}}</p></div></div>
      <div class="system-grid"><article><Database/><span><small>Cache driver</small><strong>{{data.environment.cache}}</strong></span></article><article><Layers3/><span><small>Queue connection</small><strong>{{data.environment.queue}}</strong></span></article><article><Gauge/><span><small>Debug mode</small><strong>{{data.environment.debug?'Enabled':'Disabled'}}</strong></span></article><article><BarChart3/><span><small>Mail transport</small><strong>{{data.environment.mail}}</strong></span></article></div>
      <div class="section system-help"><div class="section-copy"><h3>Deployment-managed values</h3><p>These settings are intentionally read-only here.</p></div><div class="callout"><Info/><span>PayFast mode, debug mode, mail, cache, and queue drivers come from environment configuration. Changing them requires updating the server environment and rebuilding the Laravel configuration cache.</span></div></div>
    </section>
  </div>
</main></AppShell></template>

